import React, { useEffect, useState, useMemo, useRef } from 'react';
import { Icon } from '../UI';
import { Clause, Standard, MatrixRow } from '../../types';
import { copyToClipboard, serializeMatrixData, processSourceFile, fileToBase64 } from '../../utils';
import { generateOcrContent } from '../../services/geminiService';

interface EvidenceMatrixProps {
    standard: Standard;
    selectedClauses: string[];
    matrixData: Record<string, MatrixRow[]>;
    setMatrixData: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;
}

export const EvidenceMatrix: React.FC<EvidenceMatrixProps> = ({
    standard, selectedClauses, matrixData, setMatrixData
}) => {
    const [expandedClauses, setExpandedClauses] = useState<string[]>([]);

    // Feature State: Track which row is currently processing
    const [processingRowId, setProcessingRowId] = useState<string | null>(null);
    const [listeningRowId, setListeningRowId] = useState<string | null>(null);

    const fileInputRef = useRef<HTMLInputElement>(null);
    const activeRowRef = useRef<string | null>(null); // To track which row triggered the upload
    const recognitionRef = useRef<any>(null);

    // 1. Flatten Clauses for easy lookup
    const flatClauses = useMemo(() => {
        const all: Clause[] = [];
        const traverse = (list: Clause[]) => {
            list.forEach(c => {
                all.push(c);
                if(c.subClauses) traverse(c.subClauses);
            });
        };
        standard.groups.forEach(g => traverse(g.clauses));
        return all;
    }, [standard]);

    // 2. Initialize Matrix State based on Selected Clauses
    useEffect(() => {
        setMatrixData(currentMatrix => {
            const newMatrix = { ...currentMatrix };
            let updated = false;

            selectedClauses.forEach(clauseId => {
                if (!newMatrix[clauseId]) {
                    const clause = flatClauses.find(c => c.id === clauseId);
                    if (clause) {
                        const desc = clause.description || "";
                        const reqs = desc.length > 50 
                            ? desc.split(/(?:\. |\n)/).filter(s => s.trim().length > 5) 
                            : [desc];

                        newMatrix[clauseId] = reqs.map((req, idx) => ({
                            id: `${clauseId}_req_${idx}`,
                            requirement: req.trim(),
                            evidenceInput: "",
                            status: 'pending'
                        }));
                        updated = true;
                    }
                }
            });

            if (updated) {
                if(selectedClauses.length > 0 && expandedClauses.length === 0) {
                    setExpandedClauses([selectedClauses[0]]);
                }
                return newMatrix;
            }
            return currentMatrix;
        });
    }, [selectedClauses, flatClauses, setMatrixData]);

    // --- LOGIC HANDLERS ---

    const updateRowData = (clauseId: string, rowId: string, textToAppend: string) => {
        setMatrixData(prev => ({
            ...prev,
            [clauseId]: prev[clauseId].map(row => {
                if (row.id === rowId) {
                    const currentText = row.evidenceInput || "";
                    // Smart separator: if there is text, add newline
                    const separator = currentText && textToAppend ? "\n" : "";
                    const newText = currentText + separator + textToAppend;
                    return { ...row, evidenceInput: newText, status: newText.trim() ? 'supplied' : 'pending' };
                }
                return row;
            })
        }));
    };

    const handleInputChange = (clauseId: string, rowId: string, value: string) => {
        setMatrixData(prev => ({
            ...prev,
            [clauseId]: prev[clauseId].map(row => 
                row.id === rowId 
                ? { ...row, evidenceInput: value, status: value.trim() ? 'supplied' : 'pending' } 
                : row
            )
        }));
    };

    // --- GENERIC FILE PROCESSOR (For Upload & Paste) ---
    const processFileAndInsert = async (file: File, clauseId: string, rowId: string) => {
        setProcessingRowId(rowId);
        try {
            let extractedText = "";

            if (file.type.startsWith('image/')) {
                // OCR Strategy
                const base64 = await fileToBase64(file);
                extractedText = await generateOcrContent("Transcribe the text in this image accurately for audit evidence.", base64, file.type);
            } else {
                // Document Parsing Strategy (PDF/DOCX/TXT)
                extractedText = await processSourceFile(file);
            }

            if (extractedText) {
                const header = `[Evidence Source: ${file.name}]`;
                updateRowData(clauseId, rowId, `${header}\n${extractedText}`);
            }
        } catch (error: any) {
            console.error("Matrix Processing Error", error);
            alert(`Failed to process ${file.name}: ${error.message}`);
        } finally {
            setProcessingRowId(null);
        }
    };

    // --- VOICE DICTATION ---
    const toggleDictation = (clauseId: string, rowId: string) => {
        if (listeningRowId === rowId) {
            recognitionRef.current?.stop();
            setListeningRowId(null);
        } else {
            if (recognitionRef.current) recognitionRef.current.stop();

            const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
            if (!SpeechRecognition) {
                alert("Voice-to-Text not supported in this browser.");
                return;
            }
            const recognition = new SpeechRecognition();
            recognition.continuous = false; 
            recognition.interimResults = true;
            recognition.lang = 'vi-VN'; // Could make this dynamic based on App state

            recognition.onstart = () => setListeningRowId(rowId);

            recognition.onresult = (event: any) => {
                if (event.results[0].isFinal) {
                    const transcript = event.results[0][0].transcript;
                    updateRowData(clauseId, rowId, transcript);
                }
            };

            recognition.onend = () => setListeningRowId(null);

            recognition.start();
            recognitionRef.current = recognition;
        }
    };

    // --- FILE UPLOAD (Button Click) ---
    const triggerFileUpload = (clauseId: string, rowId: string) => {
        activeRowRef.current = JSON.stringify({ clauseId, rowId }); 
        if (fileInputRef.current) {
            fileInputRef.current.value = ''; // Reset to allow same file selection
            fileInputRef.current.click();
        }
    };

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file || !activeRowRef.current) return;

        const { clauseId, rowId } = JSON.parse(activeRowRef.current);
        await processFileAndInsert(file, clauseId, rowId);
        activeRowRef.current = null;
    };

    // --- SMART PASTE (Ctrl+V) ---
    const handlePaste = async (e: React.ClipboardEvent, clauseId: string, rowId: string) => {
        const items = e.clipboardData.items;
        let hasFile = false;

        for (let i = 0; i < items.length; i++) {
            if (items[i].kind === 'file') {
                const file = items[i].getAsFile();
                if (file) {
                    hasFile = true;
                    e.preventDefault(); // Stop image binary from pasting into textarea
                    await processFileAndInsert(file, clauseId, rowId);
                }
            }
        }
        // If no file found, let default text paste happen naturally
    };

    const handleCopyMatrixToClipboard = () => {
        const text = serializeMatrixData(matrixData, selectedClauses);
        if(text) {
            copyToClipboard(text);
            alert("Matrix data copied to clipboard!"); 
        } else {
            alert("Matrix is empty.");
        }
    };

    const toggleExpand = (id: string) => {
        setExpandedClauses(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
    };

    if (selectedClauses.length === 0) {
        return (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 bg-gray-50/50 dark:bg-slate-900/50 rounded-3xl border border-dashed border-gray-200 dark:border-slate-800">
                <Icon name="LayoutList" size={48} className="mb-4 opacity-50"/>
                <p className="text-sm font-medium">Select clauses from the sidebar to start mapping evidence.</p>
            </div>
        );
    }

    return (
        <div className="h-full flex flex-col relative">
            {/* Hidden Input for File Uploads */}
            <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                accept="image/*,.pdf,.docx,.txt"
                onChange={handleFileChange}
            />

            <div className="flex-shrink-0 flex justify-end mb-2 px-1">
                 <button 
                    onClick={handleCopyMatrixToClipboard}
                    className="text-[10px] font-bold text-slate-500 hover:text-indigo-600 dark:text-slate-400 dark:hover:text-indigo-400 flex items-center gap-1 bg-white dark:bg-slate-800 px-2 py-1 rounded shadow-sm border border-gray-100 dark:border-slate-700 hover:border-indigo-200 transition-colors"
                    title="Copy Matrix content as Markdown table"
                 >
                    <Icon name="Copy" size={12}/> Copy Matrix Table
                 </button>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar space-y-4 p-1 pb-10">
                {selectedClauses.map(clauseId => {
                    const clause = flatClauses.find(c => c.id === clauseId);
                    const rows = matrixData[clauseId] || [];
                    const isExpanded = expandedClauses.includes(clauseId);
                    if (!clause) return null;

                    const filledCount = rows.filter(r => r.status === 'supplied').length;
                    const progress = Math.round((filledCount / (rows.length || 1)) * 100);

                    return (
                        <div key={clauseId} className="bg-white dark:bg-slate-900 rounded-xl border border-gray-200 dark:border-slate-800 shadow-sm overflow-hidden transition-all duration-300">
                            {/* Header */}
                            <div 
                                className="flex items-center justify-between p-3 bg-gray-50/80 dark:bg-slate-800/50 cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors"
                                onClick={() => toggleExpand(clauseId)}
                            >
                                <div className="flex items-center gap-3">
                                    <span className="text-xs font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30 px-2 py-1 rounded border border-indigo-100 dark:border-indigo-800/50">
                                        {clause.code}
                                    </span>
                                    <h4 className="text-xs font-bold text-slate-700 dark:text-slate-200">{clause.title}</h4>
                                </div>
                                <div className="flex items-center gap-3">
                                    <div className="w-16 h-1.5 bg-gray-200 dark:bg-slate-700 rounded-full overflow-hidden">
                                        <div 
                                            className={`h-full rounded-full transition-all duration-500 ${progress === 100 ? 'bg-emerald-500' : 'bg-indigo-500'}`} 
                                            style={{ width: `${progress}%` }}
                                        />
                                    </div>
                                    <Icon name={isExpanded ? "ChevronUp" : "ChevronDown"} size={14} className="text-slate-400"/>
                                </div>
                            </div>

                            {/* Body */}
                            {isExpanded && (
                                <div className="p-3 border-t border-gray-100 dark:border-slate-800">
                                    <div className="grid grid-cols-[1fr_1.5fr] gap-4 mb-2 px-2">
                                        <span className="text-[9px] font-bold text-slate-400 uppercase tracking-wider">Requirement Breakdown</span>
                                        <span className="text-[9px] font-bold text-slate-400 uppercase tracking-wider">Verified Evidence</span>
                                    </div>
                                    <div className="space-y-4">
                                        {rows.map((row) => (
                                            <div key={row.id} className="grid grid-cols-[1fr_1.5fr] gap-4 items-start p-2 hover:bg-gray-50 dark:hover:bg-slate-800/30 rounded-lg transition-colors group relative">
                                                <div className="text-[11px] text-slate-600 dark:text-slate-300 font-medium leading-relaxed pt-2">
                                                    {row.requirement}
                                                </div>

                                                <div className="relative">
                                                    <textarea
                                                        rows={3}
                                                        placeholder="Type evidence, Dictate (Mic), or Paste Image (Ctrl+V) to OCR..."
                                                        className={`w-full bg-gray-50 dark:bg-slate-950 border rounded-lg p-2 pb-8 text-xs text-slate-800 dark:text-white outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500/20 transition-all resize-y min-h-[70px] shadow-sm ${processingRowId === row.id ? 'opacity-50 pointer-events-none' : ''} ${listeningRowId === row.id ? 'border-red-400 ring-1 ring-red-400/30' : 'border-gray-200 dark:border-slate-700'}`}
                                                        value={row.evidenceInput}
                                                        onChange={(e) => handleInputChange(clauseId, row.id, e.target.value)}
                                                        onPaste={(e) => handlePaste(e, clauseId, row.id)}
                                                    />

                                                    {/* ROW TOOLBAR */}
                                                    <div className="absolute bottom-2 right-2 flex items-center gap-1">
                                                        {processingRowId === row.id ? (
                                                            <div className="flex items-center gap-2 px-2 py-1 bg-white dark:bg-slate-800 rounded-md shadow-sm border border-indigo-100 dark:border-slate-600">
                                                                <Icon name="Loader" className="animate-spin text-indigo-500" size={12}/>
                                                                <span className="text-[9px] font-bold text-indigo-500">Processing...</span>
                                                            </div>
                                                        ) : (
                                                            <>
                                                                {/* Voice Button */}
                                                                <button 
                                                                    onClick={() => toggleDictation(clauseId, row.id)}
                                                                    className={`p-1.5 rounded-md transition-all active:scale-95 ${listeningRowId === row.id ? 'bg-red-500 text-white animate-pulse shadow-red-500/30 shadow-md' : 'bg-white dark:bg-slate-800 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 border border-gray-200 dark:border-slate-700'}`}
                                                                    title={listeningRowId === row.id ? "Stop Dictation" : "Dictate Evidence"}
                                                                >
                                                                    <Icon name="Mic" size={14}/>
                                                                </button>

                                                                {/* Upload/OCR Button */}
                                                                <button 
                                                                    onClick={() => triggerFileUpload(clauseId, row.id)}
                                                                    className="p-1.5 rounded-md bg-white dark:bg-slate-800 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 border border-gray-200 dark:border-slate-700 transition-all active:scale-95"
                                                                    title="Upload Image (OCR) or PDF"
                                                                >
