            setEvidence(""); 
            setMatrixData({});
            setEvidenceTags([]);
            setSelectedClauses([]); 
            setUploadedFiles([]); 
            setAnalysisResult(null); 
            setSelectedFindings({}); 
            setFinalReportText(null); 
